windowclass.script:
function onInit()
	DB.addHandler(DB.getPath(getDatabaseNode(), "abilities"), "onChildUpdate", self.refresh);
	self.refresh();
end
function refresh()
	dpprimaryavail.refresh();
	dpsecondaryavail.refresh();
	dptotalcost.refresh();
	dpprimarycost.refresh();
	dpsecondarycost.refresh();
end
function addSkill(skl)
	local inList = false;
	local skillName = DB.getValue(skl, "name", "");
	if skillName ~= "" then
		for i, skillWindow in ipairs(skills.getWindows()) do
			if skillName == skillWindow.name.getValue() then
				inList = true;
			end
		end
	end
	if inList == false then	
		local win = skills.createWindow();
		if win then
			win.name.setValue(DB.getValue(skl, "name", "string", ""));
			win.fullname.setValue(DB.getValue(skl, "fullname", "string", ""));
			win.group.setValue(DB.getValue(skl, "group", "string", ""));
			win.stats.setValue(DB.getValue(skl, "stats", "string", ""));
			win.armorfactor.setValue(DB.getValue(skl, "armorfactor", "number", 0));
			win.type.setValue(DB.getValue(skl, "type", "number", 0));
			win.calc.setState(DB.getValue(skl, "calc", "number", 1));
			
			local skillNode = win.getDatabaseNode();
			DB.setValue(skillNode, "description", "formattedtext", DB.getValue(skl, "description", ""));
			DB.setValue(skillNode, "notes", "string", DB.getValue(skl, "notes", ""));
			DB.setValue(skillNode, "skilltype", "string", DB.getValue(skl, "skilltype", ""));
			DB.setValue(skillNode, "class", "string", DB.getValue(skl, "class", ""));
			DB.setValue(skillNode, "progression", "string", DB.getValue(skl, "progression", ""));
			DB.setValue(skillNode, "levelbonus.core", "string", DB.getValue(skl, "levelbonus.core", ""));
			DB.setValue(skillNode, "levelbonus.rm2", "string", DB.getValue(skl, "levelbonus.rm2", ""));
			DB.setValue(skillNode, "levelbonus.rmfrp", "string", DB.getValue(skl, "levelbonus.rmfrp", ""));
			DB.setValue(skillNode, "levelbonus.rmcompanion2", "string", DB.getValue(skl, "levelbonus.rmcompanion2", ""));
		end
	end
end

combobox_labeled_RMC.script:
function onInit()
	super.onInit();
	addItems(Rules_Professions.List());
end

function onValueChanged()
	local professionRealm = Rules_Professions.Realm(getValue());
	if professionRealm ~= "Pick One" then
		window.realm.setValue(professionRealm);				
	end
end

number_labeled.script:
function onValueChanged()
	if string.lower(OptionsManager.getOption("CCPP")) == string.lower(Interface.getString("option_val_on")) then
		window.max_pp.setValue(Rules_PC.PowerPoints(window.getDatabaseNode()));
	end
end

numberc_static.script:
function onInit()
	OptionsManager.registerCallback("RC44D", refresh);
	self.refresh();
end
function onClose()
	OptionsManager.unregisterCallback("RC44D", refresh);
end
function refresh()
	local charNode = window.getDatabaseNode();
	setValue(math.floor(Rules_PC.TotalDP(charNode)+0.5));
	window.dpprimaryremain.refresh();
	window.dptotalavail.refresh();
end

function onInit()
	self.refresh();
end
function refresh()
	local total = 0;
	for k,skl in ipairs(window.skills.getWindows()) do
		if skl.skillclass and skl.skillclass.getState() == 1 then
			total = total + skl.devpoints.getValue();	
		end
	end
	setValue(total);
	window.dpprimaryremain.refresh();
	window.dptotalcost.refresh();
end

function onInit()
	self.refresh();
end
function refresh()
	setValue(window.dpprimaryavail.getValue() - window.dpprimarycost.getValue());
end

					function onInit()
						OptionsManager.registerCallback("RC44D", self.refresh);
						OptionsManager.registerCallback("RC48D", self.refresh);
						OptionsManager.registerCallback("CL113", self.refresh);
						self.refresh();
					end
					function onClose()
						OptionsManager.unregisterCallback("RC44D", self.refresh);
						OptionsManager.unregisterCallback("RC48D", self.refresh);
						OptionsManager.unregisterCallback("CL113", self.refresh);
					end
					function refresh()
						local charNode = window.getDatabaseNode();
						local nSecondaryPercent = tonumber(OptionsManager.getOption("CL113")) / 100;

						setValue(math.floor(Rules_PC.TotalDP(charNode) * nSecondaryPercent));
						window.dpsecondaryremain.refresh();
						window.dptotalavail.refresh();
					end

function onInit()
	self.refresh();
end
function refresh()
	local total = 0;
	for k,skl in ipairs(window.skills.getWindows()) do
		if skl.skillclass and skl.skillclass.getState() == 2 then
			total = total + skl.devpoints.getValue();	
		end
	end
	setValue(total);
	window.dpsecondaryremain.refresh();
	window.dptotalcost.refresh();
end

function onInit()
	self.refresh();
end
function refresh()
	setValue(window.dpsecondaryavail.getValue() - window.dpsecondarycost.getValue());
end

function onInit()
	self.refresh();
end
function refresh()
	setValue(window.dpprimaryavail.getValue() + window.dpsecondaryavail.getValue());
	window.dptotalremain.refresh();
end

function onInit()
	self.refresh();
end
function refresh()
	setValue(window.dpprimarycost.getValue() + window.dpsecondarycost.getValue());
	window.dptotalremain.refresh();
end

function onInit()
	self.refresh();
end
function refresh()
	setValue(window.dptotalavail.getValue() - window.dptotalcost.getValue());
end

button_text.script:
function onButtonPress()
	for k,mod in pairs(Module.getModules()) do
		local node;
		node = DB.findNode("reference.skilllist.primaryskills.list@"..mod);
		if node then
			for k,skl in pairs(DB.getChildren(node)) do
				window.addSkill(skl);
			end
		end
	end
end

function onButtonPress()
	local charNode = window.getDatabaseNode();
	for i, skillNode in pairs(DB.getChildren(charNode, "skills")) do
		if DB.getValue(skillNode, "skillclass", 0) == 1 then
			if DB.getValue(skillNode, "rank", -1) < 1 then
				DB.deleteNode(skillNode);
			end
		end
	end
	Comm.deliverChatMessage({font="systemfont",text=DB.getValue(charNode, "name", "") .. " removed untrained primary skills."});
end

function onButtonPress()
	node = DB.findNode("skill");
	if node then
		for k,skl in pairs(DB.getChildren(node)) do
			window.addSkill(skl);
		end
	end
	for k,mod in pairs(Module.getModules()) do
		local node;
		node = DB.findNode("skill@"..mod);
		if node then
			for k,skl in pairs(DB.getChildren(node)) do
				window.addSkill(skl);
			end
		end
		node = DB.findNode("reference.skilllist.secondaryskills.list@"..mod);
		if node then
			for k,skl in pairs(DB.getChildren(node)) do
				window.addSkill(skl);
			end
		end
	end
end

function onButtonPress()
	local charNode = window.getDatabaseNode();
	for i, skillNode in pairs(DB.getChildren(charNode, "skills")) do
		if DB.getValue(skillNode, "skillclass", 0) == 2 then
			if DB.getValue(skillNode, "rank", -1) < 1 then
				DB.deleteNode(skillNode);
			end
		end
	end
	Comm.deliverChatMessage({font="systemfont",text=DB.getValue(charNode, "name", "") .. " removed untrained secondary skills."});
end

function onButtonPress()
	statmsg = "Skill Development: " .. window.name.getValue() .. " removed the following skill ranks:\r";
	count = 0;
	for i, win in ipairs(window.skills.getWindows()) do
		if win.getClass() == "charassist_skilldev_skillwindow" then
			newranks = win.newranks.getValue();
			if newranks > 0 then
				count = count + 1;
				if count > 1 then
					statmsg = statmsg .. ", ";
				end
				currentranks = win.rank.getValue();
				totalranks = currentranks - newranks;
				statmsg = statmsg .. win.name.getValue() .. " (" .. currentranks .. "-" .. newranks .. "=" .. totalranks .. ")";
				win.rank.setValue(totalranks);
			end
		end
	end
	local msg = {font = "msgfont", icon = "indicator_flagsmall", mode = "chat"};
	msg.text = statmsg;
	Comm.deliverChatMessage(msg);
end

function onButtonPress()
	statmsg = "Skill Development: " .. window.name.getValue() .. " added the following skill ranks:\r";
	count = 0;
	for i, win in ipairs(window.skills.getWindows()) do
		if win.getClass() == "charassist_skilldev_skillwindow" then
			newranks = win.newranks.getValue();
			if newranks > 0 then
				count = count + 1;
				if count > 1 then
					statmsg = statmsg .. ", ";
				end
				currentranks = win.rank.getValue();
				totalranks = currentranks + newranks;
				statmsg = statmsg .. win.name.getValue() .. " (" .. currentranks .. "+" .. newranks .. "=" .. totalranks .. ")";
				win.rank.setValue(totalranks);
			end
		end
	end
	local msg = {font = "msgfont", icon = "indicator_flagsmall", mode = "chat"};
	msg.text = statmsg;
	Comm.deliverChatMessage(msg);
end

stringcontrolX_underlined_text.script:
					local sem = false;

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						update();
					end
					function onValueChanged()
						if sem then
							return;
						end

						sem = true;
						window.parseShortName();
						sem = false;
					end
					function update()
						if sem then
							return;
						end

						sem = true;
						local nm = window.name.getValue();
						local sts = window.stats.getValue();
						local name = nm;
						if sts~="" then
							name = name .. " (" .. sts .. ")";
						end
						setValue(name);
						setTooltipText(name);
						sem = false;
					end

					function action(draginfo)
						local charNode = DB.getChild(window.getDatabaseNode(), "...");
						local rActor = ActorManager.resolveActor(charNode);
						local skillNode = window.getDatabaseNode();
						if skillNode then
							sSkillName = DB.getValue(skillNode, "name", "");
							nSkillMod = DB.getValue(skillNode, "total", 0);
							nSkillType = DB.getValue(skillNode, "type", "");
							ActionSkill.performRoll(draginfo, rActor, sSkillName, nSkillMod, nSkillType);
							return true;
						else
							Comm.deliverChatMessage({text="ERROR: Can't find skill node", font="systemfont", icon = "error"});
						end
					end
					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end
					function onDoubleClick(x,y)
						return action();
					end

numberfieldX_underlined_bold.script:
  function onValueChanged()
	if not isReadOnly() then
	  window.refresh();
	end
  end

function onInit()
	if super and super.onInit then
		super.onInit();
	end
	if string.lower(OptionsManager.getOption("CL23G")) == string.lower(Interface.getString("option_val_none")) then
		setFrame("textline",0,5,0,0);
		setReadOnly(false);
	else
		setFrame(nil);
		setReadOnly(true);
	end
end

function onValueChanged(init)
	local charNode = DB.getChild(window.getDatabaseNode(), "...");
	local skillName = window.name.getValue();
	local skillFullName = window.fullname.getValue();
	local skillTotal = getValue();
	if window.type.getValue() == 4 then
		Rules_PC.MMPenalty(charNode);
	end
	Rules_PC.SkillTotalChanged(charNode, skillName, skillFullName, skillTotal);
end

function onInit()
	refresh();
end
function onValueChanged()
	refresh();
end
function refresh()
	if Rules_Skills.ValidNewRanks(window.cost.getValue(), getValue()) then
		setValid();
		window.devpoints.setValid();
	else
		setInvalid();
		window.devpoints.setInvalid();
	end
	window.devpoints.setValue(Rules_Skills.DPCost(window.cost.getValue(), getValue()));
	local nodeChar = DB.getChild(window.getDatabaseNode(), "...");
	local w = Interface.findWindow("charassist_skilldev", DB.getPath(nodeChar));
	if w then
		w.refresh();
	end
end
